{
  "name": "OmniStock IMS",
  "description": "A professional-grade Inventory Management System featuring real-time stock tracking, automated low-stock alerts, transaction history, and a simulated barcode scanner.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Category = 'Electronics' | 'Apparel' | 'Home' | 'Office' | 'Food' | 'Other';

export interface Product {
  id: string;
  name: string;
  sku: string;
  category: Category;
  stockLevel: number;
  price: number;
  lowStockThreshold: number;
}

export type TransactionType = 'IN' | 'OUT' | 'ADJUSTMENT';

export interface Transaction {
  id: string;
  productId: string;
  productName: string;
  type: TransactionType;
  quantity: number;
  timestamp: number;
  note?: string;
}

export interface InventoryState {
  products: Product[];
  transactions: Transaction[];
}

import React from 'react';

export const CATEGORIES: string[] = ['Electronics', 'Apparel', 'Home', 'Office', 'Food', 'Other'];

export const LOW_STOCK_LIMIT = 5;

// SVG Icons as functional components
