export const createId = () => Math.random().toString(36).substr(2, 9);

import React, { useState, useEffect, useCallback } from 'react';
import { Product, Transaction, InventoryState, TransactionType } from './types';
import { loadState, saveState, createId } from './services/inventoryService';
import { Icons } from './constants.tsx';
import StatsCards from './components/StatsCards';
import InventoryTable from './components/InventoryTable';
import TransactionsList from './components/TransactionsList';
import ProductModal from './components/ProductModal';
import Scanner from './components/Scanner';

const App: React.FC = () => {
  const [state, setState] = useState<InventoryState>(loadState());
  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | undefined>();
  const [activeTab, setActiveTab] = useState<'inventory' | 'history'>('inventory');

  // Sync state to local storage whenever it changes
  useEffect(() => {
    saveState(state);
  }, [state]);

  const addTransaction = (productId: string, productName: string, type: TransactionType, quantity: number, note?: string) => {
    const newTransaction: Transaction = {
      id: createId(),
      productId,
      productName,
      type,
      quantity,
      timestamp: Date.now(),
      note,
    };
    setState(prev => ({
      ...prev,
      transactions: [newTransaction, ...prev.transactions].slice(0, 100), // Keep last 100
    }));
  };

  const handleSaveProduct = (formData: Omit<Product, 'id'>) => {
    if (editingProduct) {
      // Update existing
      setState(prev => ({
        ...prev,
        products: prev.products.map(p => 
          p.id === editingProduct.id ? { ...formData, id: p.id } : p
        )
      }));
      addTransaction(editingProduct.id, formData.name, 'ADJUSTMENT', 0, 'Details updated');
    } else {
      // Create new
      const newProduct: Product = { ...formData, id: createId() };
      setState(prev => ({
        ...prev,
        products: [...prev.products, newProduct]
      }));
      addTransaction(newProduct.id, newProduct.name, 'IN', newProduct.stockLevel, 'Initial stock');
    }
    setIsProductModalOpen(false);
    setEditingProduct(undefined);
  };

  const handleDeleteProduct = (id: string) => {
    if (window.confirm('Are you sure you want to remove this product?')) {
      const product = state.products.find(p => p.id === id);
      setState(prev => ({
        ...prev,
        products: prev.products.filter(p => p.id !== id)
      }));
      if (product) addTransaction(id, product.name, 'OUT', -product.stockLevel, 'Product deleted');
    }
  };

  const handleUpdateStock = (id: string, amount: number) => {
    setState(prev => {
      const products = prev.products.map(p => {
        if (p.id === id) {
          const newLevel = Math.max(0, p.stockLevel + amount);
          if (newLevel !== p.stockLevel) {
            addTransaction(p.id, p.name, amount > 0 ? 'IN' : 'OUT', amount);
          }
          return { ...p, stockLevel: newLevel };
        }
        return p;
      });
      return { ...prev, products };
    });
  };

  const handleScan = (sku: string) => {
    const product = state.products.find(p => p.sku.toUpperCase() === sku.toUpperCase());
    if (product) {
      handleUpdateStock(product.id, 1);
      alert(`Scanned: ${product.name}. Stock updated.`);
    } else {
      alert(`No product found for SKU: ${sku}`);
    }
    setIsScannerOpen(false);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">O</div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-600 to-violet-600 bg-clip-text text-transparent">
              OmniStock
            </h1>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsScannerOpen(true)}
              className="hidden md:flex items-center gap-2 px-3 py-1.5 text-sm font-semibold text-slate-600 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
            >
              <Icons.Scan /> Scanner
            </button>
            <button 
              onClick={() => {
                setEditingProduct(undefined);
                setIsProductModalOpen(true);
              }}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-semibold shadow-lg shadow-indigo-200 flex items-center gap-2 transition-all active:scale-95"
            >
              <Icons.Plus /> <span className="hidden sm:inline">Add Product</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 py-8">
        <StatsCards products={state.products} />

        {/* Mobile Navigation */}
        <div className="flex md:hidden bg-slate-100 p-1 rounded-xl mb-6">
          <button 
            onClick={() => setActiveTab('inventory')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 text-sm font-bold rounded-lg transition-all ${activeTab === 'inventory' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}
          >
            <Icons.Package /> Inventory
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 text-sm font-bold rounded-lg transition-all ${activeTab === 'history' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}
          >
            <Icons.History /> History
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Table Area */}
          <div className={`lg:col-span-3 ${activeTab === 'history' ? 'hidden md:block' : ''}`}>
            <InventoryTable 
              products={state.products} 
              onEdit={(p) => {
                setEditingProduct(p);
                setIsProductModalOpen(true);
              }} 
              onDelete={handleDeleteProduct}
              onUpdateStock={handleUpdateStock}
            />
          </div>

          {/* Sidebar Area */}
          <div className={`lg:col-span-1 ${activeTab === 'inventory' ? 'hidden md:block' : ''}`}>
            <TransactionsList transactions={state.transactions} />
          </div>
        </div>
      </main>

      {/* Floating Action Button for Scanner on Mobile */}
      <button 
        onClick={() => setIsScannerOpen(true)}
        className="md:hidden fixed bottom-6 right-6 w-14 h-14 bg-emerald-600 rounded-full flex items-center justify-center text-white shadow-xl shadow-emerald-200 active:scale-90 transition-transform z-40"
      >
        <Icons.Scan />
      </button>

      {/* Modals */}
      {isProductModalOpen && (
        <ProductModal 
          product={editingProduct}
          onClose={() => {
            setIsProductModalOpen(false);
            setEditingProduct(undefined);
          }}
          onSave={handleSaveProduct}
        />
      )}

      {isScannerOpen && (
        <Scanner 
          onScan={handleScan}
          onClose={() => setIsScannerOpen(false)}
        />
      )}

      {/* Footer */}
      <footer className="mt-auto py-6 border-t border-slate-200">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row justify-between items-center text-slate-400 text-xs gap-4">
          <p>© 2024 OmniStock Cloud. Production Environment Active.</p>
          <div className="flex gap-6 font-medium">
            <span className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div> Live Sync</span>
            <span>Security: AES-256 Enabled</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { Product } from '../types';
import { LOW_STOCK_LIMIT } from '../constants.tsx';

interface StatsCardsProps {
  products: Product[];
}

const StatsCards: React.FC<StatsCardsProps> = ({ products }) => {
  const totalValue = products.reduce((acc, p) => acc + (p.price * p.stockLevel), 0);
  const lowStockCount = products.filter(p => p.stockLevel <= LOW_STOCK_LIMIT).length;
  const totalStock = products.reduce((acc, p) => acc + p.stockLevel, 0);

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <p className="text-slate-500 text-sm font-medium">Total Inventory Value</p>
        <h3 className="text-2xl font-bold text-slate-900 mt-1">
          ₹{totalValue.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
        </h3>
        <p className="text-slate-400 text-xs mt-2">Across {products.length} unique products</p>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <p className="text-slate-500 text-sm font-medium">Total Units in Stock</p>
        <h3 className="text-2xl font-bold text-slate-900 mt-1">
          {totalStock.toLocaleString('en-IN')}
        </h3>
        <p className="text-emerald-500 text-xs mt-2 font-medium">Stock Healthy</p>
      </div>

      <div className={`p-6 rounded-xl shadow-sm border transition-colors ${lowStockCount > 0 ? 'bg-red-50 border-red-200' : 'bg-white border-slate-200'}`}>
        <p className="text-slate-500 text-sm font-medium">Low Stock Alerts</p>
        <h3 className={`text-2xl font-bold mt-1 ${lowStockCount > 0 ? 'text-red-600' : 'text-slate-900'}`}>
          {lowStockCount}
        </h3>
        <p className={`${lowStockCount > 0 ? 'text-red-500' : 'text-slate-400'} text-xs mt-2`}>
          {lowStockCount > 0 ? 'Requires immediate attention' : 'All items well stocked'}
        </p>
      </div>
    </div>
  );
};

export default StatsCards;

